parameters.jsCode:
const body = $input.first().json;
const content = body.content && body.content[0];
const text = content && content.text ? content.text : '';
let tasks = [];
try {
  const parsed = JSON.parse(text.replace(/^[\s\S]*?\{/, '{').replace(/\}[\s\S]*$/, '}'));
  tasks = Array.isArray(parsed.tasks) ? parsed.tasks : [];
} catch (e) {
  tasks = [];
}
return tasks.map(t => ({ json: { agent: t.agent || '', prompt: t.prompt || '' } }));

